/* ===== UI Primitives ===== */
function Bg({ children, color = C.pri, bg = C.priL }) {
  return (
    <span style={{ display: "inline-block", padding: "2px 10px", borderRadius: 20, fontSize: 11, fontWeight: 600, color, background: bg, whiteSpace: "nowrap" }}>
      {children}
    </span>
  );
}

function SB({ s }) {
  const m = {
    "confirmé": [C.ok, C.okL, "Confirmé"], "en attente": [C.wrn, C.wrnL, "En attente"],
    "en cours": [C.pri, C.priL, "En cours"], "terminé": [C.ok, C.okL, "Terminé"],
    "planifié": [C.pur, C.purL, "Planifié"], "payé": [C.ok, C.okL, "Payé"],
    "partiel": [C.wrn, C.wrnL, "Partiel"], "impayé": [C.dng, C.dngL, "Impayé"],
    "en salle": [C.treat, C.treatL, "En salle"],
    "annulé": ["#9CA3AF", "#F3F4F6", "Annulé"],
    "reporté": ["#8B5CF6", "#F3E8FF", "Reporté"],
    "absent": [C.dng, C.dngL, "Absent"]
  };
  const v = m[s] || m["en attente"];
  return <Bg color={v[0]} bg={v[1]}>{v[2]}</Bg>;
}

function Bt({ children, onClick, v = "primary", sz = "md", icon, disabled, style: sx = {} }) {
  const base = { display: "inline-flex", alignItems: "center", gap: 6, border: "none", cursor: disabled ? "not-allowed" : "pointer", fontWeight: 600, borderRadius: 8, fontFamily: "inherit", opacity: disabled ? .45 : 1 };
  const szm = { sm: { padding: "5px 11px", fontSize: 12 }, md: { padding: "8px 16px", fontSize: 13 } };
  const vm = { primary: { background: C.pri, color: C.wh }, accent: { background: C.acc, color: C.wh }, outline: { background: "transparent", color: C.pri, border: `1.5px solid ${C.pri}` }, ghost: { background: "transparent", color: C.mu }, danger: { background: C.dng, color: C.wh }, success: { background: C.ok, color: C.wh }, treat: { background: C.treat, color: C.wh }, warn: { background: C.wrn, color: C.wh } };
  return (
    <button onClick={disabled ? undefined : onClick} style={{ ...base, ...szm[sz], ...vm[v], ...sx }}>
      {icon && <Ic n={icon} s={sz === "sm" ? 14 : 16} />}{children}
    </button>
  );
}

function Cd({ children, style: sx = {} }) {
  return <div style={{ background: C.card, borderRadius: 14, border: `1px solid ${C.bd}`, padding: 24, ...sx }}>{children}</div>;
}

function Inp({ label, value, onChange, type = "text", placeholder, rows, style: sx = {} }) {
  return (
    <div style={{ marginBottom: 12, ...sx }}>
      {label && <label style={{ display: "block", fontSize: 11, fontWeight: 600, color: C.mu, marginBottom: 4, textTransform: "uppercase", letterSpacing: .5 }}>{label}</label>}
      {rows
        ? <textarea value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} rows={rows} style={{ width: "100%", padding: "8px 12px", borderRadius: 8, border: `1.5px solid ${C.bd}`, fontSize: 14, fontFamily: "inherit", resize: "vertical", boxSizing: "border-box", color: C.tx }} />
        : <input type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} style={{ width: "100%", padding: "8px 12px", borderRadius: 8, border: `1.5px solid ${C.bd}`, fontSize: 14, fontFamily: "inherit", outline: "none", boxSizing: "border-box", color: C.tx }} />
      }
    </div>
  );
}

function Sel({ label, value, onChange, options }) {
  return (
    <div style={{ marginBottom: 12 }}>
      {label && <label style={{ display: "block", fontSize: 11, fontWeight: 600, color: C.mu, marginBottom: 4, textTransform: "uppercase", letterSpacing: .5 }}>{label}</label>}
      <select value={value} onChange={e => onChange(e.target.value)} style={{ width: "100%", padding: "8px 12px", borderRadius: 8, border: `1.5px solid ${C.bd}`, fontSize: 14, fontFamily: "inherit", background: C.wh, color: C.tx }}>
        {options.map(o => <option key={o.v} value={o.v}>{o.l}</option>)}
      </select>
    </div>
  );
}

function Modal({ children, onClose, title, w = 520 }) {
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.5)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000 }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: C.card, borderRadius: 16, width: w, maxHeight: "90vh", overflow: "auto", padding: 24, boxShadow: "0 20px 60px rgba(0,0,0,.2)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 18 }}>
          <h2 style={{ fontSize: 18, fontWeight: 700 }}>{title}</h2>
          <div onClick={onClose} style={{ cursor: "pointer", color: C.mu, padding: 4 }}><Ic n="x" /></div>
        </div>
        {children}
      </div>
    </div>
  );
}

function Locked() {
  return (
    <div style={{ position: "absolute", inset: 0, background: "rgba(238,242,247,.9)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", zIndex: 10, borderRadius: 14 }}>
      <Ic n="lock" s={28} />
      <span style={{ marginTop: 6, fontWeight: 600, color: C.mu, fontSize: 12 }}>Réservé au Docteur</span>
    </div>
  );
}

function PH() {
  return null;
}

function PF() {
  return null;
}

function DChart({ pid, chart, onUpdate, sel, setSel, ro }) {
  const pc = chart[pid] || {};
  const sc = (cd) => {
    if (!sel || ro) return;
    if (onUpdate) onUpdate(pid, sel, cd);
  };

  return (
    <div>
      {!ro && (
        <div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginBottom: 12 }}>
          {Object.entries(TC).map(([k, v]) => (
            <div key={k} onClick={() => sc(k)} style={{ display: "flex", alignItems: "center", gap: 4, padding: "3px 8px", borderRadius: 5, cursor: sel ? "pointer" : "default", border: `1.5px solid ${v.b}`, background: v.c, fontSize: 10, fontWeight: 600, opacity: sel ? 1 : .4 }}>
              <span style={{ width: 7, height: 7, borderRadius: 2, background: v.b }} />{v.l}
            </div>
          ))}
        </div>
      )}
      <div style={{ background: "#F8FAFC", borderRadius: 10, padding: 14, border: `1px solid ${C.bd}` }}>
        <div style={{ textAlign: "center", fontSize: 10, fontWeight: 700, color: C.mu, marginBottom: 4, textTransform: "uppercase" }}>Maxillaire</div>
        <div style={{ display: "flex", gap: 2, justifyContent: "center", flexWrap: "wrap" }}>
          {TU.map(t => {
            const cd = TC[pc[t] || "sain"];
            return (
              <div key={t} onClick={() => !ro && setSel(sel === t ? null : t)} style={{ width: 34, height: 42, borderRadius: 6, background: cd.c, border: `${sel === t ? 2.5 : 1.5}px solid ${sel === t ? C.pri : cd.b}`, display: "flex", alignItems: "center", justifyContent: "center", cursor: ro ? "default" : "pointer", flexShrink: 0 }}>
                <span style={{ fontSize: 10, fontWeight: 700, color: pc[t] === "manquante" ? "#94A3B8" : C.tx }}>{t}</span>
              </div>
            );
          })}
        </div>
        <div style={{ borderTop: `2px dashed ${C.bd}`, margin: "8px 0" }} />
        <div style={{ display: "flex", gap: 2, justifyContent: "center", flexWrap: "wrap" }}>
          {TL.map(t => {
            const cd = TC[pc[t] || "sain"];
            return (
              <div key={t} onClick={() => !ro && setSel(sel === t ? null : t)} style={{ width: 34, height: 42, borderRadius: 6, background: cd.c, border: `${sel === t ? 2.5 : 1.5}px solid ${sel === t ? C.pri : cd.b}`, display: "flex", alignItems: "center", justifyContent: "center", cursor: ro ? "default" : "pointer", flexShrink: 0 }}>
                <span style={{ fontSize: 10, fontWeight: 700, color: pc[t] === "manquante" ? "#94A3B8" : C.tx }}>{t}</span>
              </div>
            );
          })}
        </div>
        <div style={{ textAlign: "center", fontSize: 10, fontWeight: 700, color: C.mu, marginTop: 4, textTransform: "uppercase" }}>Mandibule</div>
      </div>
      {sel && !ro && (
        <div style={{ marginTop: 8, padding: 8, background: C.priL, borderRadius: 6, fontSize: 12 }}>
          <strong>Dent #{sel}</strong> — {TC[pc[sel] || "sain"].l}
        </div>
      )}
    </div>
  );
}

